class Solution {
    public boolean doesAliceWin(String s) {
        int n = s.length();
        int[] dp = new int[n + 1];
        dp[n] = 0;
        for (int i = n - 1; i >= 0; i--) {
            int cnt = 0;
            for (int j = i; j < n; j++) {
                if ("aeiou".indexOf(s.charAt(j)) != -1) {
                    cnt++;
                }
                if ((cnt & 1) == 1) {
                    dp[i] = Math.max(dp[i], dp[j + 1] + 1);
                }
            }
        }
        return dp[0] % 2 == 1;
    }
}
